class Solution:
    def countSubTrees(self, n, edges, labels):
        from collections import deque
        graph = [[] for _ in range(n)]
        for a, b in edges:
            graph[a].append(b)
            graph[b].append(a)
        parent = [-1] * n
        visited = [False] * n
        visited[0] = True
        order = [0]
        dq = deque([0])
        while dq:
            u = dq.popleft()
            for v in graph[u]:
                if not visited[v]:
                    visited[v] = True
                    parent[v] = u
                    order.append(v)
                    dq.append(v)
        count = [[0] * 26 for _ in range(n)]
        for node in order:
            count[node][ord(labels[node]) - 97] += 1
        ans = [0] * n
        for node in reversed(order):
            idx = ord(labels[node]) - 97
            ans[node] = count[node][idx]
            p = parent[node]
            if p != -1:
                for k in range(26):
                    count[p][k] += count[node][k]
        return ans

