var countSubTrees = function(n, edges, labels) {
    const graph = Array.from({ length: n }, () => []);
    for (const [a, b] of edges) {
        graph[a].push(b);
        graph[b].push(a);
    }
    const count = Array.from({ length: n }, () => new Array(26).fill(0));
    const ans = new Array(n).fill(0);
    const parent = new Array(n).fill(-1);
    const visited = new Array(n).fill(false);
    visited[0] = true;
    const nodeStack = [0];
    const idxStack = [0];
    while (nodeStack.length) {
        const node = nodeStack[nodeStack.length - 1];
        let i = idxStack[idxStack.length - 1];
        let descended = false;
        while (i < graph[node].length) {
            const nxt = graph[node][i];
            i++;
            if (!visited[nxt]) {
                visited[nxt] = true;
                parent[nxt] = node;
                idxStack[idxStack.length - 1] = i;
                nodeStack.push(nxt);
                idxStack.push(0);
                descended = true;
                break;
            }
        }
        if (!descended) {
            idxStack[idxStack.length - 1] = i;
            const idx = labels.charCodeAt(node) - 97;
            count[node][idx] += 1;
            const p = parent[node];
            if (p !== -1) {
                for (let k = 0; k < 26; k++) count[p][k] += count[node][k];
            }
            ans[node] = count[node][idx];
            nodeStack.pop();
            idxStack.pop();
        }
    }
    return ans;
};
